import React from 'react';

const About = () => {
  return (
    <section id="about" className="section">
      <div className="container">
        <h2>About Me</h2>
        <p>
          Passionate civil engineer with 5+ years of experience in structural design, project management,
          and sustainable infrastructure development. Skilled in AutoCAD, Revit, and STAAD.Pro.
        </p>
      </div>
    </section>
  );
};

export default About;
